    if year % 4 == 0:
        if year % 100 == 0:
            if year % 400 == 0:
                is_leap = True
            else:
                is_leap = False
        else:
            is_leap = True

    # Convert expected object to boolean
    expected = obj.lower() in ['true', 'yes', '1']

    # Return whether the claim is correct
    return is_leap == expected

