def verify(subject: str, predicate: str, obj: str) -> bool:
    # Check if predicate matches 'is_prime'
    if predicate != 'is_prime':
        return False

    # Convert subject to integer
    try:
        num = int(subject)
    except ValueError:
        return False

    # Prime number check
    if num <= 1:
        return False

    if num <= 3:
        return True

    if num % 2 == 0 or num % 3 == 0:
        return False

    i = 5
    while i * i <= num:
