        return False

    # Helper function to check if a number is prime
    def is_prime(n):
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(n**0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

    # Parse the subject as an integer
    num = int(subject)

    # Determine the actual prime status of 9
    # 9 = 3 × 3, so it's not prime
    actual_prime = is_prime(num)

    # Validate against the object claim
    if obj == 'true':
        return actual_prime
    elif obj == 'false':
        return not actual_prime

    return False

